// Two equivalent notations
const names: string[] = ['Alice', 'Bob', 'Charlie'];
const scores: Array<number> = [95, 87, 100];

// Nested arrays
const matrix: number[][] = [
  [1, 2, 3],
  [4, 5, 6],
];

// Array of objects
interface User { id: number; name: string }
const users: User[] = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
];

// Union element type
const mixed: (string | number)[] = ['hello', 42, 'world', 100];

// Empty array — TypeScript infers never[] without annotation
const items: string[] = [];   // annotate when initialising empty
items.push('first');          // OK — string is expected

const nums: number[] = [1, 2, 3, 4, 5];

const doubled: number[]  = nums.map(n => n * 2);
const evens:   number[]  = nums.filter(n => n % 2 === 0);
const sum:     number    = nums.reduce((acc, n) => acc + n, 0);
const first:   number | undefined = nums.find(n => n > 3);
const hasLarge: boolean  = nums.some(n => n > 4);
const allPos:   boolean  = nums.every(n => n > 0);

// flatMap — useful in Angular when items expand
const words: string[][] = [['Hello', 'world'], ['foo', 'bar']];
const flat: string[] = words.flatMap(w => w);

// TypeScript catches type errors in callbacks
nums.map(n => n.toUpperCase()); // TS2339 — toUpperCase does not exist on number

const ids: readonly number[] = [1, 2, 3];
// ids.push(4);    // TS2339 — Property 'push' does not exist on readonly number[]
// ids[0] = 99;    // TS2542 — Cannot assign to '0' because it is read-only

// ReadonlyArray<T> is equivalent
const labels: ReadonlyArray<string> = ['home', 'about', 'contact'];

// Angular: signal holds a readonly tuple/array
import { signal } from '@angular/core';
const items = signal<readonly string[]>(['a', 'b', 'c']);
// Mutation must go through signal.update()
items.update(prev => [...prev, 'd']);

// Function parameter — signal intent (caller cannot mutate)
function renderList(items: readonly string[]): string {
  return items.join(', ');
}

// [string, number] — exactly two elements
const nameAndAge: [string, number] = ['Alice', 30];
const name = nameAndAge[0]; // string
const age  = nameAndAge[1]; // number

// Accessing beyond the tuple length is an error
// const x = nameAndAge[2]; // TS2493 — Tuple type has no element at index '2'

// Wrong types are caught
// const bad: [string, number] = [30, 'Alice']; // TS2322

// Multi-element tuples
type RGB = [red: number, green: number, blue: number];
const white: RGB = [255, 255, 255];

// Destructuring (idiomatic with tuples)
const [first, second] = nameAndAge;
// first: string, second: number

type Point2D = [x: number, y: number];
type Point3D = [x: number, y: number, z: number];
type DateRange = [start: Date, end: Date];

const origin: Point2D = [0, 0];
