type Config = [host: string, port: number, ssl?: boolean];

const a: Config = ['localhost', 3000];        // ssl omitted
const b: Config = ['example.com', 443, true]; // ssl provided

// Access returns the union of the type and undefined
const ssl = b[2]; // boolean | undefined

type StringAndNumbers = [string, ...number[]];
const data: StringAndNumbers = ['total', 1, 2, 3, 4]; // variadic tail

// Leading rest
type NumbersAndString = [...number[], string];
const r: NumbersAndString = [1, 2, 3, 'end'];

// Spread into a function
function tag(label: string, ...values: number[]): string {
  return `[${label}] ${values.join(', ')}`;
}

const args: [string, ...number[]] = ['sum', 10, 20, 30];
tag(...args); // spreads the tuple as arguments

// Array destructuring
const colors = ['red', 'green', 'blue'];
const [primary, secondary, tertiary] = colors;
// All: string

// Skip elements
const [, second, , fourth = 'default'] = colors;
// second: string, fourth: string

// Rest element
const [head, ...tail] = colors;
// head: string, tail: string[]

// Tuple destructuring — types per position
type Pair = [string, number];
const pair: Pair = ['score', 100];
const [label, value] = pair;
// label: string, value: number

// Nested
const matrix: [number, number][] = [[1, 2], [3, 4]];
for (const [x, y] of matrix) {
  console.log(x + y); // x: number, y: number
}

// Angular @for with $index
// @for (item of items; track item.id; let i = $index) — i is number

// Simple pair return
function minMax(nums: number[]): [min: number, max: number] {
  return [Math.min(...nums), Math.max(...nums)];
}

const [min, max] = minMax([3, 1, 4, 1, 5, 9]);
// min: number, max: number — better than { min, max } when order is obvious

// Result type: [data, error]
function tryParse<T>(raw: string): [T, null] | [null, Error] {
  try {
    return [JSON.parse(raw) as T, null];
  } catch (e) {
    return [null, e as Error];
  }
}

const [data, err] = tryParse<{ id: number }>('{"id":1}');
if (err) {
  console.error(err.message);
} else {
  console.log(data.id); // data: { id: number } — narrowed
}

// Angular: custom hook-like pattern
function useLoading(): [boolean, (value: boolean) => void] {
  const loading = signal(false);
  const setLoading = (v: boolean) => loading.set(v);
  return [loading(), setLoading];
}

const [isLoading, setLoading] = useLoading();

interface Product {
  id: number;
  name: string;
  price: number;
}

@Component({ selector: 'app-product-list', template: '' })
class ProductListComponent {
  @Input() products: Product[] = [];
  @Input() selectedIds: readonly number[] = [];
  @Output() selectionChange = new EventEmitter<number[]>();

  toggleSelection(id: number): void {
    const current = [...this.selectedIds];
    const idx = current.indexOf(id);
    if (idx >= 0) {
      current.splice(idx, 1);
    } else {
      current.push(id);
    }
    this.selectionChange.emit(current);
  }
}

import { signal, computed } from '@angular/core';

interface Task {
  id: number;
  title: string;
  done: boolean;
}

// Signal holding an array
const tasks = signal<Task[]>([]);

// Computed derivations
const pending   = computed(() => tasks().filter(t => !t.done));
const completed = computed(() => tasks().filter(t => t.done));
const count     = computed(() => tasks().length);

// Immutable update patterns
function addTask(title: string): void {
  tasks.update(prev => [
    ...prev,
    { id: Date.now(), title, done: false },
  ]);
}

function toggleTask(id: number): void {
  tasks.update(prev =>
    prev.map(t => t.id === id ? { ...t, done: !t.done } : t)
  );
}

function removeTask(id: number): void {
  tasks.update(prev => prev.filter(t => t.id !== id));
}

import { Observable, of } from 'rxjs';
