const events$ = of('click', 'keydown', 'scroll');
const log$: Observable<string[]> = events$.pipe(
  scan((acc: string[], event) => [...acc, event], [])
);

const words = ['banana', 'apple', 'cherry'];
words.sort();            // mutates; alphabetical: ['apple', 'banana', 'cherry']

const nums = [10, 2, 30, 4];
// Wrong: nums.sort() returns ['10', '2', '30', '4'] — coerced to strings
nums.sort((a, b) => a - b); // correct ascending numeric sort

interface Product { name: string; price: number }
