// Extract the element type of any typed array
type ElementOf<T extends readonly unknown[]> = T[number];
type NumEl = ElementOf<number[]>; // number

// Without as const — widened to string[]
const directions = ['north', 'south', 'east', 'west'];
type Dir1 = typeof directions[number]; // string

// With as const — narrowed to literal union
const DIRECTIONS = ['north', 'south', 'east', 'west'] as const;
type Direction = typeof DIRECTIONS[number];
// 'north' | 'south' | 'east' | 'west'

function move(dir: Direction): void { /* ... */ }
move('north');   // OK
// move('up');  // TS2345 — Argument of type "up" is not assignable

// Tuple literals also benefit from as const
const pair = [1, 'hello'] as const;
// type: readonly [1, 'hello'] — not (string | number)[]

type Head<T extends unknown[]> = T extends [infer H, ...unknown[]] ? H : never;
type Tail<T extends unknown[]> = T extends [unknown, ...infer R] ? R : [];
type Prepend<T, Arr extends unknown[]> = [T, ...Arr];
type Concat<A extends unknown[], B extends unknown[]> = [...A, ...B];

type A = [string, number];
type B = [boolean, Date];
type AB = Concat<A, B>; // [string, number, boolean, Date]

type H = Head<A>; // string
type T = Tail<A>; // [number]

// Practical: typed event handler params
type ClickHandler = [event: MouseEvent, timestamp: number];
type ScrollHandler = [event: Event];
type AllHandlers = Concat<ClickHandler, ScrollHandler>;
// [event: MouseEvent, timestamp: number, event: Event]

// Strongly-typed curry using tuple rest
function curry<A extends unknown[], R>(
  fn: (...args: A) => R
): A extends [infer First, ...infer Rest]
  ? (first: First) => (...rest: Rest) => R
  : () => R {
  return ((first: A[0]) => (...rest: unknown[]) => fn(first, ...rest)) as never;
}

// Practical spread pattern: wrap a callback with context
function withLogging<A extends unknown[], R>(
  label: string,
  fn: (...args: A) => R
): (...args: A) => R {
  return (...args: A) => {
    console.log(\`[\${label}] called with\`, args);
    return fn(...args);
  };
}

const add = (a: number, b: number): number => a + b;
const loggedAdd = withLogging('add', add);
loggedAdd(1, 2); // [add] called with [1, 2]  →  3
